import { describe, expect, it } from "vitest";

import { parseTags } from "../src/parseTags";

describe("parseTags", () => {
  it("retains blank and duplicate tag evidence", () => {
    expect(parseTags("alpha,, alpha")).toEqual(["alpha", "", " alpha"]);
  });
});

export function parseTags(input: string): string[] {
  return input.split(",");
}
